 * Includes error handling for unexpected inputs.
 */

public class MergeSort {

    // Main method to test the merge sort function
    public static void main(String[] args) {
        int[] array = {38, 27, 43, 3, 9, 82, 10};
        try {
            int[] sortedArray = mergeSort(array);
            for (int num : sortedArray) {
                System.out.print(num + " ");
            }
        } catch (IllegalArgumentException e) {
            System.out.println(e.getMessage());
        }
    }

    /**
     * Merge sort function to sort the array in ascending order.
     * @param array the array to be sorted
     * @return the sorted array
     * @throws IllegalArgumentException if the input array contains negative numbers
     */
    public static int[] mergeSort(int[] array) {
        // Validate the input array
        for (int num : array) {
            if (num < 0) {
                throw new IllegalArgumentException("Array contains negative numbers, which are not allowed.");
            }
        }

        if (array.length <= 1) {
            return array;
        }

        int mid = array.length / 2;
        int[] left = mergeSort(Arrays.copyOfRange(array, 0, mid));
        int[] right = mergeSort(Arrays.copyOfRange(array, mid, array.length));

        return merge(left, right);
    }

    /**
     * Merge two sorted arrays into one sorted array.
     * @param left the left sorted array
     * @param right the right sorted array
     * @return the merged sorted array
     */
    private static int[] merge(int[] left, int[] right) {
        int[] merged = new int[left.length + right.length];
        int i = 0, j = 0, k = 0;

        while (i < left.length && j < right.length) {
            if (left[i] < right[j]) {
                merged[k++] = left[i++];
            } else {
                merged[k++] = right[j++];
            }
