#!/usr/bin/perl
use strict;
use warnings;
use PDF::API2;
use Text::PDF::Text;

# Function to extract metadata from the PDF
sub extract_metadata {
    my ($pdf_file) = @_;
    my $pdf = PDF::API2->open($pdf_file);
    my $info = $pdf->info;
    my $date = $info->get( 'CreationDate' );
    my $author = $info->get( 'Author' );
    return ($date, $author);
}

# Function to extract table information from the PDF
sub extract_table_info {
    my ($pdf_file) = @_;
    my $pdf_text = Text::PDF::Text->new($pdf_file);
    my @lines = $pdf_text->extract;
    my $table_info = '';

    foreach my $line (@lines) {
        # Assuming table information is in a specific format, e.g., "Table 1: Data Overview"
        if ($line =~ /Table\s+\d+:\s+(.+)$/) {
            $table_info .= $1 . "\n";
        }
    }

    return $table_info;
}

# Main script
my $pdf_file = 'example.pdf';  # Replace with your PDF file path
my ($date, $author) = extract_metadata($pdf_file);
print "Date: $date\n";
print "Author: $author\n";

my $table_info = extract_table_info($pdf_file);
print "Table Information:\n$table_info\n";
